program LIPDecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math;

const
  PI = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : NPOINTS;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : NPOINTS;
    QUADS    : NUMQUADS;
    DIST     : real;
    N_PTS    : NPTYPE;
    K_PTS    : POINTRANGE;
    A_PTS    : POINTRANGE;
    B_PTS    : POINTRANGE;
    C_PTS    : POINTRANGE;
    D_PTS    : POINTRANGE;
    E_PTS    : POINTRANGE;
    F_PTS    : POINTRANGE;
    G_PTS    : POINTRANGE;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := sqrt(sqr(x2 - x1) + sqr(y2 - y1));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := Abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

function Angle(x1, y1, x2, y2, x3, y3: real): real;
var
  dx1, dy1, dx2, dy2, dot, cross, mag1, mag2: real;
begin
  dx1 := x1 - x2;
  dy1 := y1 - y2;
  dx2 := x3 - x2;
  dy2 := y3 - y2;

  mag1 := sqrt(sqr(dx1) + sqr(dy1));
  mag2 := sqrt(sqr(dx2) + sqr(dy2));

  if (mag1 = 0.0) or (mag2 = 0.0) then
  begin
    Angle := -1.0;
    Exit;
  end;

  dot := dx1 * dx2 + dy1 * dy2;
  Angle := arccos(dot / (mag1 * mag2));
end;

function CircleContainsThreePoints(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  d12, d23, d13: real;
  cx, cy, r: real;
  a, b, c, d, e, f, g: real;
begin
  d12 := Distance(x1, y1, x2, y2);
  d23 := Distance(x2, y2, x3, y3);
  d13 := Distance(x1, y1, x3, y3);

  if (REALCOMPARE(d12, 2 * radius) <> GT) and
     (REALCOMPARE(d23, 2 * radius) <> GT) and
     (REALCOMPARE(d13, 2 * radius) <> GT) then
  begin
    a := x2 - x1;
    b := y2 - y1;
    c := x3 - x1;
    d := y3 - y1;
    e := a * (x1 + x2) + b * (y1 + y2);
    f := c * (x1 + x3) + d * (y1 + y3);
    g := 2 * (a * (y3 - y2) - b * (x3 - x2));

    if g = 0.0 then
    begin
      CircleContainsThreePoints := True;
      Exit;
    end;

    cx := (d * e - b * f) / g;
    cy := (a * f - c * e) / g;
    r := Distance(cx, cy, x1, y1);

    CircleContainsThreePoints := REALCOMPARE(r, radius) <> GT;
  end
  else
    CircleContainsThreePoints := False;
end;

function DistanceToLine(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, lineLenSq, t, projX, projY: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  lineLenSq := sqr(dx) + sqr(dy);

  if lineLenSq = 0.0 then
  begin
    DistanceToLine := Distance(px, py, x1, y1);
    Exit;
  end;

  t := ((px - x1) * dx + (py - y1) * dy) / lineLenSq;

  if t < 0.0 then
    DistanceToLine := Distance(px, py, x1, y1)
  else if t > 1.0 then
    DistanceToLine := Distance(px, py, x2, y2)
  else
  begin
    projX := x1 + t * dx;
    projY := y1 + t * dy;
    DistanceToLine := Distance(px, py, projX, projY);
  end;
end;

function GetQuadrant(x, y: real): integer;
begin
  if x >= 0.0 then
  begin
    if y >= 0.0 then
      GetQuadrant := 1
    else
      GetQuadrant := 4;
  end
  else
  begin
    if y >= 0.0 then
      GetQuadrant := 2
    else
      GetQuadrant := 3;
  end;
end;

procedure LIC1;
var
  i: integer;
  dist: real;
begin
  CMV[1] := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := True;
      Exit;
    end;
  end;
end;

procedure LIC2;
var
  i: integer;
begin
  CMV[2] := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not CircleContainsThreePoints(X[i], Y[i], X[i + 1], Y[i + 1],
                                     X[i + 2], Y[i + 2], PARAMETERS.RADIUS1) then
    begin
      CMV[2] := True;
      Exit;
    end;
  end;
end;

procedure LIC3;
var
  i: integer;
  ang: real;
begin
  CMV[3] := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    ang := Angle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if ang >= 0.0 then
    begin
      if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[3] := True;
        Exit;
      end;
    end;
  end;
end;

procedure LIC4;
var
  i: integer;
  area: real;
begin
  CMV[4] := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := True;
      Exit;
    end;
  end;
end;

procedure LIC5;
var
  i, j, quad, numQuadsUsed: integer;
  quads: array[1..4] of boolean;
begin
  CMV[5] := False;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quads[1] := False;
    quads[2] := False;
    quads[3] := False;
    quads[4] := False;

    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      quad := GetQuadrant(X[j], Y[j]);
      quads[quad] := True;
    end;

    numQuadsUsed := 0;
    for j := 1 to 4 do
      if quads[j] then
        Inc(numQuadsUsed);

    if numQuadsUsed > PARAMETERS.QUADS then
    begin
      CMV[5] := True;
      Exit;
    end;
  end;
end;

procedure LIC6;
var
  i: integer;
begin
  CMV[6] := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1], X[i]) = LT then
    begin
      CMV[6] := True;
      Exit;
    end;
  end;
end;

procedure LIC7;
var
  i, j: integer;
  dist: real;
begin
  CMV[7] := False;
  if NUMPOINTS < 3 then
    Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    if (X[i] = X[i + PARAMETERS.N_PTS - 1]) and
       (Y[i] = Y[i + PARAMETERS.N_PTS - 1]) then
    begin
      for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
      begin
        dist := Distance(X[j], Y[j], X[i], Y[i]);
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          CMV[7] := True;
          Exit;
        end;
      end;
    end
    else
    begin
      for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
      begin
        dist := DistanceToLine(X[j], Y[j], X[i], Y[i],
                               X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          CMV[7] := True;
          Exit;
        end;
      end;
    end;
  end;
end;

procedure LIC8;
var
  i: integer;
  dist: real;
begin
  CMV[8] := False;
  if NUMPOINTS < 3 then
    Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[8] := True;
      Exit;
    end;
  end;
end;

procedure LIC9;
var
  i: integer;
begin
  CMV[9] := False;
  if NUMPOINTS < 5 then
    Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if not CircleContainsThreePoints(X[i], Y[i],
                                     X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                                     X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                                     Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                                     PARAMETERS.RADIUS1) then
    begin
      CMV[9] := True;
      Exit;
    end;
  end;
end;

procedure LIC10;
var
  i: integer;
  ang: real;
begin
  CMV[10] := False;
  if NUMPOINTS < 5 then
    Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    ang := Angle(X[i], Y[i],
                 X[i + PARAMETERS.C_PTS + 1], Y[i + PARAMETERS.C_PTS + 1],
                 X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2],
                 Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2]);
    if ang >= 0.0 then
    begin
      if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[10] := True;
        Exit;
      end;
    end;
  end;
end;

procedure LIC11;
var
  i: integer;
  area: real;
begin
  CMV[11] := False;
  if NUMPOINTS < 5 then
    Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i],
                        X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
                        X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2],
                        Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[11] := True;
      Exit;
    end;
  end;
end;

procedure LIC12;
var
  i: integer;
begin
  CMV[12] := False;
  if NUMPOINTS < 3 then
    Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1], X[i]) = LT then
    begin
      CMV[12] := True;
      Exit;
    end;
  end;
end;

procedure LIC13;
var
  i: integer;
  dist: real;
  part1, part2: boolean;
begin
  CMV[13] := False;
  if NUMPOINTS < 3 then
    Exit;

  part1 := False;
  part2 := False;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      part1 := True;
    if REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT then
      part2 := True;
  end;

  CMV[13] := part1 and part2;
end;

procedure LIC14;
var
  i: integer;
  part1, part2: boolean;
begin
  CMV[14] := False;
  if NUMPOINTS < 5 then
    Exit;

  part1 := False;
  part2 := False;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if not CircleContainsThreePoints(X[i], Y[i],
                                     X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                                     X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                                     Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                                     PARAMETERS.RADIUS1) then
      part1 := True;
    if CircleContainsThreePoints(X[i], Y[i],
                                 X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                                 X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                                 Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                                 PARAMETERS.RADIUS2) then
      part2 := True;
  end;

  CMV[14] := part1 and part2;
end;

procedure LIC15;
var
  i: integer;
  area: real;
  part1, part2: boolean;
begin
  CMV[15] := False;
  if NUMPOINTS < 5 then
    Exit;

  part1 := False;
  part2 := False;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i],
                        X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
                        X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2],
                        Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      part1 := True;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
      part2 := True;
  end;

  CMV[15] := part1 and part2;
end;

procedure CalculateCMV;
begin
  LIC1;
  LIC2;
  LIC3;
  LIC4;
  LIC5;
  LIC6;
  LIC7;
  LIC8;
  LIC9;
  LIC10;
  LIC11;
  LIC12;
  LIC13;
  LIC14;
  LIC15;
end;

procedure CalculatePUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
        Continue;

      case LCM[i, j] of
        NOTUSED: PUM[i, j] := True;
        ANDD: PUM[i, j] := CMV[i] and CMV[j];
        ORR: PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;
end;

procedure CalculateFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := True;
    end
    else
    begin
      allTrue := True;
      for j := 1 to 15 do
      begin
        if (i <> j) and (not PUM[i, j]) then
        begin
          allTrue := False;
          Break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;
end;

procedure CalculateLaunch;
var
  i: integer;
begin
  LAUNCH := True;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := False;
      Exit;
    end;
  end;
end;

procedure DECIDE;
begin
  CalculateCMV;
  CalculatePUM;
  CalculateFUV;
  CalculateLaunch;
end;

function FindString(const s, sub: string; startPos: integer): integer;
var
  i: integer;
begin
  FindString := 0;
  if startPos > Length(s) then
    Exit;
  for i := startPos to Length(s) - Length(sub) + 1 do
  begin
    if Copy(s, i, Length(sub)) = sub then
    begin
      FindString := i;
      Exit;
    end;
  end;
end;

function ExtractNumber(const s: string; var pos: integer): real;
var
  numStr: string;
  code: integer;
begin
  numStr := '';
  while (pos <= Length(s)) and (s[pos] in [' ', ',', '[', ']', '{', '}', ':', '"']) do
    Inc(pos);

  while (pos <= Length(s)) and (s[pos] in ['-', '+', '0'..'9', '.', 'e', 'E']) do
  begin
    numStr := numStr + s[pos];
    Inc(pos);
  end;

  Val(numStr, ExtractNumber, code);
end;

function ExtractInteger(const s: string; var pos: integer): integer;
var
  numStr: string;
  code: integer;
begin
  numStr := '';
  while (pos <= Length(s)) and (s[pos] in [' ', ',', '[', ']', '{', '}', ':', '"']) do
    Inc(pos);

  while (pos <= Length(s)) and (s[pos] in ['-', '+', '0'..'9']) do
  begin
    numStr := numStr + s[pos];
    Inc(pos);
  end;

  Val(numStr, ExtractInteger, code);
end;

function ExtractString(const s: string; var pos: integer): string;
var
  inQuotes: boolean;
begin
  ExtractString := '';
  while (pos <= Length(s)) and (s[pos] in [' ', ',', '[', ']', '{', '}', ':']) do
    Inc(pos);

  if (pos <= Length(s)) and (s[pos] = '"') then
  begin
    Inc(pos);
    inQuotes := True;
  end
  else
    inQuotes := False;

  while (pos <= Length(s)) do
  begin
    if inQuotes and (s[pos] = '"') then
    begin
      Inc(pos);
      Break;
    end;
    if (not inQuotes) and (s[pos] in [',', ']', '}']) then
      Break;
    ExtractString := ExtractString + s[pos];
    Inc(pos);
  end;
end;

function ExtractBoolean(const s: string; var pos: integer): boolean;
var
  boolStr: string;
begin
  boolStr := ExtractString(s, pos);
  ExtractBoolean := (boolStr = 'true');
end;

procedure ParseInput;
var
  inputStr: string;
  pos, i, j: integer;
  fieldPos: integer;
begin
  inputStr := '';
  while not EOF do
  begin
    readln(inputStr);
    if inputStr <> '' then
      Break;
  end;

  fieldPos := FindString(inputStr, '"numpoints"', 1);
  pos := fieldPos + 11;
  NUMPOINTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"x"', 1);
  pos := fieldPos + 3;
  for i := 1 to NUMPOINTS do
    X[i] := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"y"', 1);
  pos := fieldPos + 3;
  for i := 1 to NUMPOINTS do
    Y[i] := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"LENGTH1"', 1);
  pos := fieldPos + 9;
  PARAMETERS.LENGTH1 := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"RADIUS1"', 1);
  pos := fieldPos + 9;
  PARAMETERS.RADIUS1 := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"EPSILON"', 1);
  pos := fieldPos + 9;
  PARAMETERS.EPSILON := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"AREA1"', 1);
  pos := fieldPos + 7;
  PARAMETERS.AREA1 := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"Q_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.Q_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"QUADS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.QUADS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"DIST"', 1);
  pos := fieldPos + 6;
  PARAMETERS.DIST := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"N_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.N_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"K_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.K_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"A_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.A_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"B_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.B_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"C_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.C_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"D_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.D_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"E_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.E_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"F_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.F_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"G_PTS"', 1);
  pos := fieldPos + 7;
  PARAMETERS.G_PTS := ExtractInteger(inputStr, pos);

  fieldPos := FindString(inputStr, '"LENGTH2"', 1);
  pos := fieldPos + 9;
  PARAMETERS.LENGTH2 := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"RADIUS2"', 1);
  pos := fieldPos + 9;
  PARAMETERS.RADIUS2 := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"AREA2"', 1);
  pos := fieldPos + 7;
  PARAMETERS.AREA2 := ExtractNumber(inputStr, pos);

  fieldPos := FindString(inputStr, '"lcm"', 1);
  pos := fieldPos + 5;
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      case ExtractString(inputStr, pos) of
        'NOTUSED': LCM[i, j] := NOTUSED;
        'ORR': LCM[i, j] := ORR;
        'ANDD': LCM[i, j] := ANDD;
      end;
    end;
  end;

  fieldPos := FindString(inputStr, '"pum_diag"', 1);
  pos := fieldPos + 10;
  for i := 1 to 15 do
    PUM[i, i] := ExtractBoolean(inputStr, pos);
end;

procedure WriteOutput;
var
  i, j: integer;
begin
  Write('{"cmv":[');
  for i := 1 to 15 do
  begin
    if CMV[i] then
      Write('true')
    else
      Write('false');
    if i < 15 then
      Write(',');
  end;
  Write('],"pum":[');
  for i := 1 to 15 do
  begin
    Write('[');
    for j := 1 to 15 do
    begin
      if PUM[i, j] then
        Write('true')
      else
        Write('false');
      if j < 15 then
        Write(',');
    end;
    Write(']');
    if i < 15 then
      Write(',');
  end;
  Write('],"fuv":[');
  for i := 1 to 15 do
  begin
    if FUV[i] then
      Write('true')
    else
      Write('false');
    if i < 15 then
      Write(',');
  end;
  Write('],"launch":');
  if LAUNCH then
    Write('true')
  else
    Write('false');
  WriteLn('}');
end;

begin
  ParseInput;
  DECIDE;
  WriteOutput;
end.
